import React, { useState, useRef, useEffect } from 'react';

const FoodDetectionApp = () => {
  // 상태 관리
  const [currentMode, setCurrentMode] = useState('home');
  const [images, setImages] = useState([]);
  const [detectionResults, setDetectionResults] = useState({});
  const [ocrResults, setOcrResults] = useState({});
  const [geminiResults, setGeminiResults] = useState({});
  const [fridgeIngredients, setFridgeIngredients] = useState([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [confidence, setConfidence] = useState(0.5);
  const [statusMessage, setStatusMessage] = useState('해먹기 또는 사먹기를 선택하세요.');
  const [isDragOver, setIsDragOver] = useState(false);
  const [activeTab, setActiveTab] = useState('detection');
  const [showSaveButton, setShowSaveButton] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [userId, setUserId] = useState('user_' + Date.now());
  const [clearBeforeAnalysis, setClearBeforeAnalysis] = useState(false);
  const [selectedImageIndex, setSelectedImageIndex] = useState(0);
  const [processingImageIndex, setProcessingImageIndex] = useState(-1);
  
  // 직접 추가 기능 관련 상태
  const [showManualAdd, setShowManualAdd] = useState(false);
  const [manualIngredientName, setManualIngredientName] = useState('');
  const [manualIngredientQuantity, setManualIngredientQuantity] = useState(1);
  const [isAddingManual, setIsAddingManual] = useState(false);
  
  // Refs
  const fileInputRef = useRef(null);
  const analysisTimeoutRef = useRef(null);
  const manualInputRef = useRef(null);
  
  // API 설정
  const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://192.168.0.19:8080';
  const GEMINI_API_KEY = process.env.REACT_APP_GEMINI_API_KEY || 'AIzaSyBBHRss0KLaEeeAgggsVOIGQ_zhS5ssDGw';
  const GEMINI_API_URL = process.env.REACT_APP_GEMINI_API_URL || 'https://generativelanguage.googleapis.com/v1/models/gemini-1.5-flash:generateContent';

  // 브랜드 패턴 데이터베이스
  const BRAND_PATTERNS = {
    '농심': ['신라면', '너구리', '안성탕면', '짜파게티', '육개장', '새우탕', '올리브'],
    '오뚜기': ['진라면', '스낵면', '컵누들', '참치마요', '카레', '3분카레'],
    '롯데': ['초코파이', '가나초콜릿', '빼빼로', '칸쵸', '몽쉘', '꼬깔콘'],
    '해태': ['홈런볼', '맛동산', '오예스', '허니버터칩', '신당동떡볶이'],
    '삼양': ['불닭볶음면', '까르보불닭', '삼양라면', '짜장불닭'],
    '빙그레': ['바나나우유', '메로나', '투게더', '딸기우유'],
    '동원': ['참치캔', '김치찌개', '양반김', '리챔'],
    'CJ': ['햇반', '비비고', '백설']
  };

  // 아이콘 컴포넌트들
  const CookingIcon = () => <span className="text-2xl">👨‍🍳</span>;
  const EatingIcon = () => <span className="text-2xl">🍽️</span>;
  const UploadIcon = () => <span className="text-sm">📁</span>;
  const EyeIcon = () => <span className="text-sm">👁️</span>;
  const BrainIcon = () => <span className="text-sm">🧠</span>;
  const FileTextIcon = () => <span className="text-sm">📄</span>;
  const SettingsIcon = () => <span className="text-sm">⚙️</span>;
  const FridgeIcon = () => <span className="text-lg">🧊</span>;
  const BackIcon = () => <span className="text-sm">←</span>;
  const PlusIcon = () => <span className="text-sm">+</span>;
  const MinusIcon = () => <span className="text-sm">-</span>;
  const DeleteIcon = () => <span className="text-sm">🗑️</span>;
  const SaveIcon = () => <span className="text-sm">💾</span>;
  const CheckIcon = () => <span className="text-sm">✅</span>;
  const CloseIcon = () => <span className="text-sm">✕</span>;
  const EditIcon = () => <span className="text-sm">✏️</span>;
  const AllIcon = () => <span className="text-sm">🔄</span>;
  const LoadingSpinner = () => (
    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
  );

  // useEffect hooks
  useEffect(() => {
    return () => {
      if (analysisTimeoutRef.current) {
        clearTimeout(analysisTimeoutRef.current);
      }
    };
  }, []);

  useEffect(() => {
    if (showManualAdd && manualInputRef.current) {
      manualInputRef.current.focus();
    }
  }, [showManualAdd]);

  // 브랜드 탐지 함수
  const detectBrandAndProduct = (text) => {
    if (!text) return { brand: null, product: null, confidence: 0 };
    
    const preprocessed = text.replace(/[^\w\s가-힣]/g, ' ').replace(/\s+/g, ' ').trim();
    const textUpper = preprocessed.toUpperCase();
    
    let detectedBrand = null;
    let detectedProduct = null;
    let maxConfidence = 0;
    
    Object.entries(BRAND_PATTERNS).forEach(([brand, products]) => {
      const brandUpper = brand.toUpperCase();
      const hasBrand = preprocessed.includes(brand) || textUpper.includes(brandUpper);
      
      products.forEach(product => {
        const productUpper = product.toUpperCase();
        const hasProduct = preprocessed.includes(product) || textUpper.includes(productUpper);
        
        if (hasProduct) {
          let confidence = product.length;
          if (hasBrand) {
            confidence += brand.length + 10;
          }
          
          if (confidence > maxConfidence) {
            detectedBrand = brand;
            detectedProduct = product;
            maxConfidence = confidence;
          }
        }
      });
    });
    
    return {
      brand: detectedBrand,
      product: detectedProduct,
      confidence: maxConfidence,
      fullName: detectedBrand && detectedProduct ? `${detectedBrand} ${detectedProduct}` : null
    };
  };

  // 식품명 추출 함수
  const extractFoodNameWithBrands = (geminiResult, detectedBrand) => {
    if (!geminiResult) {
      return detectedBrand?.fullName || null;
    }
    
    try {
      const firstLine = geminiResult.trim().split('\n')[0].trim();
      const prefixes = [
        "추론된 식품:", "식품명:", "제품명:", "상품명:", "분석 결과:", 
        "결과:", "답변:", "식품:", "추론 결과:", "판단 결과:"
      ];
      
      let cleanResult = firstLine;
      prefixes.forEach(prefix => {
        if (cleanResult.startsWith(prefix)) {
          cleanResult = cleanResult.substring(prefix.length).trim();
        }
      });
      
      cleanResult = cleanResult.replace(/\*\*/g, '').replace(/\*/g, '');
      
      if (cleanResult.includes('(') && cleanResult.includes(')')) {
        cleanResult = cleanResult.split('(')[0].trim();
      }
      
      if (detectedBrand?.fullName) {
        const detectedName = detectedBrand.fullName;
        
        if (detectedBrand.brand && detectedBrand.product && 
            cleanResult.includes(detectedBrand.brand) && cleanResult.includes(detectedBrand.product)) {
          if (cleanResult.length <= detectedName.length + 15) {
            return cleanResult;
          }
        }
        
        return detectedName;
      }
      
      return cleanResult || null;
      
    } catch (error) {
      console.error('❌ 식품명 추출 중 오류:', error);
      return detectedBrand?.fullName || geminiResult;
    }
  };

  // Gemini API 호출 함수
  const callGeminiAPIWithBrands = async (prompt, text, detectionResults = null) => {
    try {
      const brandDetection = detectBrandAndProduct(text);
      let brandContext = "";
      
      if (brandDetection?.fullName) {
        brandContext = `\n\n🏪 중요: 텍스트에서 '${brandDetection.fullName}' 브랜드/제품이 직접 탐지되었습니다.`;
      } else if (brandDetection?.brand) {
        brandContext = `\n\n🏪 참고: 텍스트에서 '${brandDetection.brand}' 브랜드가 탐지되었습니다.`;
      }
      
      let detectionContext = "";
      if (detectionResults && detectionResults.length > 0) {
        const detectedClasses = detectionResults.filter(det => det.class !== 'other').map(det => det.class);
        if (detectedClasses.length > 0) {
          detectionContext = `\n\n🎯 참고: 이미지에서 다음 식품들이 탐지되었습니다: ${detectedClasses.join(', ')}`;
        }
      }
      
      const enhancedPrompt = `${prompt}${brandContext}${detectionContext}

🏪 주요 브랜드별 대표 제품들:
• 농심: 신라면, 너구리, 안성탕면, 짜파게티
• 오뚜기: 진라면, 컵누들, 참치마요, 3분카레
• 롯데: 초코파이, 가나초콜릿, 빼빼로
• 해태: 홈런볼, 맛동산, 허니버터칩
• 삼양: 불닭볶음면, 까르보불닭
• 빙그레: 바나나우유, 메로나, 딸기우유
• 동원: 참치캔, 양반김, 리챔
• CJ: 햇반, 비비고

⚠️ 중요: 실제 유통 중인 브랜드+제품명 조합을 최우선으로 추론하세요!`;
      
      const response = await fetch(`${GEMINI_API_URL}?key=${GEMINI_API_KEY}`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          contents: [{
            parts: [{
              text: enhancedPrompt
            }]
          }],
          generationConfig: {
            temperature: 0.05,
            topK: 20,
            topP: 0.7,
            maxOutputTokens: 100,
          }
        }),
      });

      if (response.ok) {
        const data = await response.json();
        const result = data.candidates?.[0]?.content?.parts?.[0]?.text || '';
        
        const finalResult = extractFoodNameWithBrands(result, brandDetection);
        return finalResult;
      } else {
        throw new Error(`Gemini API 오류: ${response.status}`);
      }
    } catch (error) {
      console.error('❌ Gemini API 호출 실패:', error);
      
      const brandDetection = detectBrandAndProduct(text);
      if (brandDetection?.fullName) {
        return brandDetection.fullName;
      }
      
      throw error;
    }
  };

  // 기본 번역 함수
  const translateToKoreanFallback = (englishName) => {
    const basicTranslations = {
      'apple': '사과',
      'banana': '바나나', 
      'carrot': '당근',
      'tomato': '토마토',
      'orange': '오렌지',
      'onion': '양파',
      'potato': '감자',
      'cucumber': '오이',
      'lettuce': '상추',
      'broccoli': '브로콜리',
      'eggs': '계란',
      'egg': '계란',
      'milk': '우유',
      'bread': '빵',
      'rice': '쌀',
      'chicken': '닭고기',
      'beef': '소고기',
      'pork': '돼지고기',
    };
    
    return basicTranslations[englishName.toLowerCase()] || englishName;
  };

  // Gemini 번역 함수
  const translateToKoreanWithGemini = async (englishName) => {
    try {
      const prompt = `다음 영어 식재료명을 정확한 한국어로 번역해주세요.

영어 식재료: "${englishName}"

🇰🇷 번역 규칙:
- 한국에서 실제 사용되는 식재료/음식 이름으로 번역
- 한국어 한 단어 또는 간단한 구문으로만 답변
- 불필요한 설명이나 문장 금지

예시: 
- apple → 사과
- banana → 바나나  
- chicken → 닭고기

한국어 번역:`;

      const translatedText = await callGeminiAPIWithBrands(prompt, englishName);
      const cleanTranslation = translatedText.replace(/[^\가-힣a-zA-Z\s]/g, '').trim();
      
      if (cleanTranslation && cleanTranslation.length > 0) {
        return cleanTranslation;
      } else {
        throw new Error('번역 결과가 비어있음');
      }
    } catch (error) {
      return translateToKoreanFallback(englishName);
    }
  };

  // 식재료 관리 함수들
  const updateIngredientQuantity = (id, newQuantity) => {
    if (newQuantity < 0) return;
    setFridgeIngredients(prev => 
      prev.map(ingredient => 
        ingredient.id === id 
          ? { ...ingredient, quantity: newQuantity }
          : ingredient
      )
    );
  };

  const removeIngredient = (id) => {
    setFridgeIngredients(prev => 
      prev.filter(ingredient => ingredient.id !== id)
    );
  };

  const addManualIngredient = () => {
    const ingredientName = manualIngredientName.trim();
    
    if (!ingredientName) {
      alert('식재료 이름을 입력해주세요.');
      return;
    }

    if (manualIngredientQuantity < 1) {
      alert('수량은 1개 이상이어야 합니다.');
      return;
    }

    setIsAddingManual(true);

    const existingIngredient = fridgeIngredients.find(item => 
      item.name.trim().toLowerCase() === ingredientName.toLowerCase()
    );

    if (existingIngredient) {
      setFridgeIngredients(prev => 
        prev.map(ingredient => 
          ingredient.id === existingIngredient.id
            ? { ...ingredient, quantity: ingredient.quantity + manualIngredientQuantity }
            : ingredient
        )
      );
      setStatusMessage(`✅ ${ingredientName} 수량이 ${manualIngredientQuantity}개 추가되었습니다.`);
    } else {
      const maxId = fridgeIngredients.length > 0 ? Math.max(...fridgeIngredients.map(item => item.id)) : 0;
      const newIngredient = {
        id: maxId + 1,
        name: ingredientName,
        quantity: manualIngredientQuantity,
        confidence: 1.0,
        source: 'manual'
      };

      setFridgeIngredients(prev => [...prev, newIngredient]);
      setStatusMessage(`✅ ${ingredientName} ${manualIngredientQuantity}개가 추가되었습니다.`);
    }

    setShowSaveButton(true);
    setManualIngredientName('');
    setManualIngredientQuantity(1);
    setShowManualAdd(false);
    setIsAddingManual(false);

    setTimeout(() => {
      setStatusMessage('식재료가 추가되었습니다.');
    }, 3000);
  };

  const closeManualAdd = () => {
    setShowManualAdd(false);
    setManualIngredientName('');
    setManualIngredientQuantity(1);
  };

  const handleManualInputKeyPress = (e) => {
    if (e.key === 'Enter') {
      addManualIngredient();
    }
  };

  // MongoDB 관련 함수들
  const saveToMongoDB = async () => {
    if (fridgeIngredients.length === 0) {
      setStatusMessage('저장할 식재료가 없습니다.');
      return;
    }

    setIsSaving(true);

    try {
      const saveData = {
        userId: userId,
        ingredients: fridgeIngredients,
        timestamp: new Date().toISOString(),
        totalCount: fridgeIngredients.reduce((sum, item) => sum + item.quantity, 0),
        totalTypes: fridgeIngredients.length
      };

      const saveResponse = await fetch(`${API_BASE_URL}/api/fridge/save`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(saveData),
      });

      if (saveResponse.ok) {
        const result = await saveResponse.json();
        setStatusMessage(`✅ 냉장고 데이터가 성공적으로 저장되었습니다! (총 ${fridgeIngredients.length}종류)`);
        setShowSaveButton(false);
        
        setTimeout(() => {
          setStatusMessage('저장 완료');
        }, 3000);
      } else {
        const errorData = await saveResponse.json();
        throw new Error(errorData.message || '저장 실패');
      }
    } catch (error) {
      console.error('❌ MongoDB 저장 실패:', error);
      
      try {
        const localData = {
          userId: userId,
          ingredients: fridgeIngredients,
          timestamp: new Date().toISOString(),
          totalCount: fridgeIngredients.reduce((sum, item) => sum + item.quantity, 0),
          totalTypes: fridgeIngredients.length
        };
        
        localStorage.setItem(`fridge_${userId}`, JSON.stringify(localData));
        setStatusMessage(`📱 로컬에 저장되었습니다 (총 ${fridgeIngredients.length}종류) - 서버 연결 실패`);
        setShowSaveButton(false);
      } catch (localError) {
        setStatusMessage(`❌ 저장 실패: ${error.message}`);
      }
    } finally {
      setIsSaving(false);
    }
  };

  const loadFromMongoDB = async () => {
    try {
      const loadResponse = await fetch(`${API_BASE_URL}/api/fridge/load/${userId}`);

      if (loadResponse.ok) {
        const result = await loadResponse.json();
        
        if (result.ingredients && result.ingredients.length > 0) {
          setFridgeIngredients(result.ingredients);
          setStatusMessage(`📥 저장된 데이터를 불러왔습니다 (${result.totalTypes}종류, ${result.totalCount}개)`);
          setShowSaveButton(false);
        } else {
          setStatusMessage('저장된 데이터가 없습니다.');
        }
      } else {
        throw new Error('데이터 로드 실패');
      }
    } catch (error) {
      console.error('❌ MongoDB 로드 실패:', error);
      
      try {
        const localData = localStorage.getItem(`fridge_${userId}`);
        if (localData) {
          const parsed = JSON.parse(localData);
          setFridgeIngredients(parsed.ingredients || []);
          setStatusMessage(`📱 로컬 데이터를 불러왔습니다 (${parsed.totalTypes || 0}종류)`);
          setShowSaveButton(false);
        } else {
          setStatusMessage('저장된 데이터가 없습니다.');
        }
      } catch (localError) {
        setStatusMessage('데이터 로드 실패');
      }
    }
  };

  const addToFridge = (newIngredients) => {
    setFridgeIngredients(prevIngredients => {
      const updatedIngredients = [...prevIngredients];
      let maxId = updatedIngredients.length > 0 ? Math.max(...updatedIngredients.map(item => item.id)) : 0;

      newIngredients.forEach(newItem => {
        const existingItemIndex = updatedIngredients.findIndex(item => 
          item.name.trim().toLowerCase() === newItem.name.trim().toLowerCase()
        );

        if (existingItemIndex !== -1) {
          const oldQuantity = updatedIngredients[existingItemIndex].quantity;
          updatedIngredients[existingItemIndex] = {
            ...updatedIngredients[existingItemIndex],
            quantity: oldQuantity + newItem.quantity,
            confidence: Math.max(
              updatedIngredients[existingItemIndex].confidence || 0, 
              newItem.confidence || 0
            ),
            source: newItem.source || updatedIngredients[existingItemIndex].source
          };
        } else {
          const newIngredient = {
            id: ++maxId,
            name: newItem.name.trim(),
            quantity: newItem.quantity,
            confidence: newItem.confidence || 0.8,
            source: newItem.source || 'analysis'
          };
          updatedIngredients.push(newIngredient);
        }
      });
      
      if (updatedIngredients.length > 0) {
        setShowSaveButton(true);
      }
      
      return updatedIngredients;
    });
  };

  // 네비게이션 함수들
  const goToHome = () => {
    setCurrentMode('home');
    setImages([]);
    setDetectionResults({});
    setOcrResults({});
    setGeminiResults({});
    setStatusMessage('해먹기 또는 사먹기를 선택하세요.');
    setActiveTab('detection');
    setShowManualAdd(false);
    setSelectedImageIndex(0);
    setProcessingImageIndex(-1);
  };

  const startHomeCooking = () => {
