  // 드래그 앤 드롭 핸들러
  const handleDragOver = (e) => {
    e.preventDefault();
    setIsDragOver(true);
  };

  const handleDragLeave = (e) => {
    e.preventDefault();
    setIsDragOver(false);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragOver(false);
    
    const files = Array.from(e.dataTransfer.files);
    const imageFiles = files.filter(file => file.type.startsWith('image/'));
    
    if (imageFiles.length > 0) {
      processImageFiles(imageFiles);
    } else {
      setStatusMessage('이미지 파일만 업로드 가능합니다.');
    }
  };

  // 이미지 처리 함수들
  const processImageFiles = (files) => {
    const imageFiles = Array.from(files).filter(file => file.type.startsWith('image/'));
    
    if (imageFiles.length === 0) {
      setStatusMessage('이미지 파일만 업로드 가능합니다.');
      return;
    }

    const processedImages = [];
    let processedCount = 0;

    imageFiles.forEach((file, index) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        processedImages[index] = {
          id: Date.now() + index,
          file: file,
          dataUrl: e.target.result,
          name: file.name,
          size: file.size,
          processed: false
        };
        
        processedCount++;
        if (processedCount === imageFiles.length) {
          setImages(prev => [...prev, ...processedImages.filter(img => img)]);
          setSelectedImageIndex(images.length);
          setStatusMessage(`✅ ${imageFiles.length}개 이미지가 추가되었습니다.`);
        }
      };
      
      reader.onerror = () => {
        processedCount++;
        if (processedCount === imageFiles.length) {
          const validImages = processedImages.filter(img => img);
          if (validImages.length > 0) {
            setImages(prev => [...prev, ...validImages]);
            setSelectedImageIndex(images.length);
            setStatusMessage(`✅ ${validImages.length}개 이미지가 추가되었습니다.`);
          }
        }
      };
      
      reader.readAsDataURL(file);
    });
  };

  const handleImageLoad = (event) => {
    const files = Array.from(event.target.files);
    if (files.length > 0) {
      processImageFiles(files);
    }
  };

  const removeImage = (imageId) => {
    setImages(prev => {
      const filtered = prev.filter(img => img.id !== imageId);
      if (filtered.length === 0) {
        setSelectedImageIndex(0);
        setStatusMessage('모든 이미지가 삭제되었습니다.');
      } else if (selectedImageIndex >= filtered.length) {
        setSelectedImageIndex(filtered.length - 1);
      }
      return filtered;
    });
    
    setDetectionResults(prev => {
      const newResults = { ...prev };
      delete newResults[imageId];
      return newResults;
    });
    
    setOcrResults(prev => {
      const newResults = { ...prev };
      delete newResults[imageId];
      return newResults;
    });
    
    setGeminiResults(prev => {
      const newResults = { ...prev };
      delete newResults[imageId];
      return newResults;
    });
  };

  // 향상된 분석 함수들
  const analyzeImageAdvanced = async (imageIndex) => {
    if (imageIndex < 0 || imageIndex >= images.length) {
      setStatusMessage('유효하지 않은 이미지입니다.');
      return;
    }

    const image = images[imageIndex];
    if (!image || !image.file) {
      setStatusMessage('이미지 파일이 없습니다.');
      return;
    }

    if (isProcessing) {
      return;
    }

    setIsProcessing(true);
    setProcessingImageIndex(imageIndex);

    try {
      setProcessingStep(`이미지 ${imageIndex + 1} 고급 분석 중...`);
      setStatusMessage(`이미지 ${imageIndex + 1} 고급 분석 중...`);

      let finalIngredients = [];

      // 1단계: Detection API 호출
      setProcessingStep(`1/3 - 객체 탐지 중...`);
      const detectFormData = new FormData();
      detectFormData.append('file', image.file);
      detectFormData.append('confidence', confidence);

      let detectionResult = null;
      try {
        const detectResponse = await fetch(`${API_BASE_URL}/api/detect`, {
          method: 'POST',
          body: detectFormData,
        });

        if (detectResponse.ok) {
          detectionResult = await detectResponse.json();
          setDetectionResults(prev => ({
            ...prev,
            [image.id]: detectionResult
          }));

          if (detectionResult.detections && detectionResult.detections.length > 0) {
            for (let detection of detectionResult.detections) {
              const koreanName = await translateToKoreanWithGemini(detection.class);
              finalIngredients.push({
                name: koreanName,
                quantity: 1,
                confidence: detection.confidence,
                source: 'detection'
              });
            }
          }
        }
      } catch (error) {
        console.error('Detection 실패:', error);
      }

      // 2단계: OCR API 호출
      setProcessingStep(`2/3 - 텍스트 추출 중...`);
      const ocrFormData = new FormData();
      ocrFormData.append('file', image.file);

      let ocrResult = null;
      try {
        const ocrResponse = await fetch(`${API_BASE_URL}/api/ocr`, {
          method: 'POST',
          body: ocrFormData,
        });

        if (ocrResponse.ok) {
          ocrResult = await ocrResponse.json();
          setOcrResults(prev => ({
            ...prev,
            [image.id]: ocrResult
          }));
        }
      } catch (error) {
        console.error('OCR 실패:', error);
      }

      // 3단계: Gemini AI 분석
      setProcessingStep(`3/3 - AI 분석 중...`);
      let geminiResult = null;
      try {
        if (ocrResult && ocrResult.text) {
          const prompt = `다음은 식품 포장지나 라벨에서 추출된 텍스트입니다. 이 텍스트를 분석하여 실제 식품명을 정확히 추론해주세요.

추출된 텍스트: "${ocrResult.text}"

분석 요구사항:
1. 브랜드명과 제품명을 종합적으로 고려
2. 한국에서 실제 판매되는 제품명으로 추론
3. 포장재 재질이나 무관한 텍스트는 무시
4. 정확한 제품명만 간단히 답변

추론된 식품명:`;

          geminiResult = await callGeminiAPIWithBrands(
            prompt, 
            ocrResult.text, 
            detectionResult?.detections || []
          );

          if (geminiResult) {
            setGeminiResults(prev => ({
              ...prev,
              [image.id]: {
                text: geminiResult,
                originalPrompt: prompt,
                extractedText: ocrResult.text
              }
            }));

            // Gemini 결과를 식재료에 추가
            const existingNames = finalIngredients.map(item => item.name.toLowerCase());
            if (!existingNames.includes(geminiResult.toLowerCase())) {
              finalIngredients.push({
                name: geminiResult,
                quantity: 1,
                confidence: 0.9,
                source: 'gemini'
              });
            }
          }
        }
      } catch (error) {
        console.error('Gemini 분석 실패:', error);
      }

      // 결과 처리
      if (finalIngredients.length > 0) {
        addToFridge(finalIngredients);
        setStatusMessage(`✅ 이미지 ${imageIndex + 1} 고급 분석 완료: ${finalIngredients.length}개 식재료 추가`);
        
        setImages(prev => prev.map((img, idx) => 
          idx === imageIndex ? { ...img, processed: true } : img
        ));
      } else {
        setStatusMessage(`❌ 이미지 ${imageIndex + 1}: 식재료를 찾을 수 없습니다.`);
      }

    } catch (error) {
      console.error('고급 분석 오류:', error);
      setStatusMessage(`❌ 이미지 ${imageIndex + 1} 고급 분석 중 오류가 발생했습니다.`);
    } finally {
      setIsProcessing(false);
      setProcessingImageIndex(-1);
      setProcessingStep('');
    }
  };

  // 간단한 분석 함수 (기본 버전)
  const analyzeImage = async (imageIndex) => {
    if (imageIndex < 0 || imageIndex >= images.length) {
      setStatusMessage('유효하지 않은 이미지입니다.');
      return;
    }

    const image = images[imageIndex];
    if (!image || !image.file) {
      setStatusMessage('이미지 파일이 없습니다.');
      return;
    }

    if (isProcessing) {
      return;
    }

    setIsProcessing(true);
    setProcessingImageIndex(imageIndex);

    try {
      setProcessingStep(`이미지 ${imageIndex + 1} 분석 중...`);
      setStatusMessage(`이미지 ${imageIndex + 1} 분석 중...`);

      // Detection API 호출
      const detectFormData = new FormData();
      detectFormData.append('file', image.file);
      detectFormData.append('confidence', confidence);

      const detectResponse = await fetch(`${API_BASE_URL}/api/detect`, {
        method: 'POST',
        body: detectFormData,
      });

      let finalIngredients = [];

      if (detectResponse.ok) {
        const result = await detectResponse.json();
        setDetectionResults(prev => ({
          ...prev,
          [image.id]: result
        }));

        if (result.detections && result.detections.length > 0) {
          // Detection 결과를 한국어로 번역
          for (let detection of result.detections) {
            const koreanName = await translateToKoreanWithGemini(detection.class);
            finalIngredients.push({
              name: koreanName,
              quantity: 1,
              confidence: detection.confidence,
              source: 'detection'
            });
          }
        }
      }

      if (finalIngredients.length > 0) {
        addToFridge(finalIngredients);
        setStatusMessage(`✅ 이미지 ${imageIndex + 1} 분석 완료: ${finalIngredients.length}개 식재료 추가`);
        
        setImages(prev => prev.map((img, idx) => 
          idx === imageIndex ? { ...img, processed: true } : img
        ));
      } else {
        setStatusMessage(`❌ 이미지 ${imageIndex + 1}: 식재료를 찾을 수 없습니다.`);
      }

    } catch (error) {
      console.error('분석 오류:', error);
      setStatusMessage(`❌ 이미지 ${imageIndex + 1} 분석 중 오류가 발생했습니다.`);
    } finally {
      setIsProcessing(false);
      setProcessingImageIndex(-1);
      setProcessingStep('');
    }
  };

  const analyzeAllImages = async () => {
    if (images.length === 0) {
      setStatusMessage('분석할 이미지가 없습니다.');
      return;
    }

    if (isProcessing) {
      return;
    }

    setIsProcessing(true);
    
    try {
      if (clearBeforeAnalysis) {
        setFridgeIngredients([]);
      }

      setStatusMessage(`전체 ${images.length}개 이미지 일괄 분석을 시작합니다...`);
      
      for (let i = 0; i < images.length; i++) {
        if (!images[i].processed) {
          await analyzeImageAdvanced(i);
          if (i < images.length - 1) {
            await new Promise(resolve => setTimeout(resolve, 1000));
          }
        }
      }
      
      setStatusMessage(`✅ 전체 일괄 분석 완료!`);

    } catch (error) {
      console.error('일괄 분석 오류:', error);
      setStatusMessage('❌ 일괄 분석 중 오류가 발생했습니다.');
    } finally {
      setIsProcessing(false);
      setProcessingImageIndex(-1);
      setProcessingStep('');
    }
  };

  const testServerConnection = async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/health`);
      if (response.ok) {
        const result = await response.json();
        setStatusMessage('서버 연결 성공');
      } else {
        setStatusMessage(`서버 응답 오류: ${response.status}`);
      }
    } catch (error) {
      setStatusMessage(`서버 연결 실패: ${error.message}`);
    }
  };

  // 렌더링
  if (currentMode === 'home') {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 flex items-center justify-center p-4">
        <div className="w-full max-w-md">
          <div className="text-center mb-8">
            <div className="text-6xl mb-4">🍽️</div>
            <h1 className="text-2xl font-bold text-gray-800 mb-2">
              스마트 푸드 매니저
            </h1>
            <p className="text-gray-600 text-sm">
              AI로 똑똑하게 식사 계획하기
            </p>
          </div>

          <div className="space-y-4">
            <button
              onClick={startHomeCooking}
              className="w-full bg-white rounded-2xl shadow-lg p-6 transition-all duration-300 hover:shadow-xl hover:scale-105 active:scale-95"
            >
              <div className="flex items-center gap-4">
                <div className="bg-green-100 rounded-full p-3">
                  <CookingIcon />
                </div>
                <div className="text-left flex-1">
                  <h3 className="text-lg font-semibold text-gray-800">해먹기</h3>
                  <p className="text-sm text-gray-600">냉장고 식재료로 요리하기</p>
                </div>
                <div className="text-gray-400">→</div>
              </div>
            </button>

            <button
              onClick={startEating}
              className="w-full bg-white rounded-2xl shadow-lg p-6 transition-all duration-300 hover:shadow-xl hover:scale-105 active:scale-95"
            >
              <div className="flex items-center gap-4">
                <div className="bg-orange-100 rounded-full p-3">
                  <EatingIcon />
                </div>
                <div className="text-left flex-1">
                  <h3 className="text-lg font-semibold text-gray-800">사먹기</h3>
                  <p className="text-sm text-gray-600">맛집 추천 및 주문하기</p>
                </div>
                <div className="text-gray-400">→</div>
              </div>
            </button>
          </div>

          <div className="mt-8 text-center">
            <button
              onClick={testServerConnection}
              className="text-sm text-gray-500 hover:text-gray-700 underline"
            >
              서버 연결 테스트
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (currentMode === 'eating') {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="text-center">
          <div className="text-6xl mb-4">🚧</div>
          <h2 className="text-xl font-semibold text-gray-800 mb-4">사먹기 기능 개발 중</h2>
          <p className="text-gray-600 mb-6">곧 멋진 기능으로 찾아뵙겠습니다!</p>
          <button
            onClick={goToHome}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
          >
            홈으로 돌아가기
          </button>
        </div>
      </div>
    );
  }

  // 해먹기 모드 메인 화면
  return (
    <div className="min-h-screen bg-gray-50">
      <div className="w-full max-w-md sm:max-w-2xl lg:max-w-6xl mx-auto p-3 sm:p-4 lg:p-6">
        
        {/* 헤더 */}
        <div className="bg-white rounded-xl shadow-sm p-4 mb-4">
          <div className="flex items-center gap-3 mb-2">
            <button
              onClick={goToHome}
              className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
            >
              <BackIcon />
            </button>
            <CookingIcon />
            <h1 className="text-lg sm:text-xl lg:text-2xl font-bold text-gray-800 truncate">
              해먹기 - 냉장고 식재료 분석
            </h1>
          </div>
          <p className="text-xs sm:text-sm text-gray-600 hidden sm:block ml-12">
            냉장고 사진을 업로드하고 AI로 식재료를 자동 인식해보세요
          </p>
        </div>

        {/* 액션 버튼들 */}
        <div className="bg-white rounded-xl shadow-sm p-4 mb-4">
          <div className="grid grid-cols-1 sm:grid-cols-4 gap-3 mb-4">
            <input
              type="file"
              accept="image/*"
              onChange={handleImageLoad}
              ref={fileInputRef}
              className="hidden"
              multiple
            />
            
            <button
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center justify-center gap-2 py-3 px-4 bg-blue-600 text-white rounded-lg font-medium transition-all duration-200 active:scale-95 hover:bg-blue-700"
            >
              <UploadIcon />
              <span className="text-sm">이미지 업로드</span>
            </button>

            <button
              onClick={() => images.length > 0 && selectedImageIndex >= 0 ? analyzeImage(selectedImageIndex) : null}
              disabled={images.length === 0 || isProcessing}
              className="flex items-center justify-center gap-2 py-3 px-4 bg-green-600 text-white rounded-lg font-medium transition-all duration-200 active:scale-95 hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
            >
              {isProcessing && processingImageIndex === selectedImageIndex ? <LoadingSpinner /> : <BrainIcon />}
              <span className="text-sm">빠른 분석</span>
            </button>

            <button
              onClick={() => images.length > 0 && selectedImageIndex >= 0 ? analyzeImageAdvanced(selectedImageIndex) : null}
              disabled={images.length === 0 || isProcessing}
              className="flex items-center justify-center gap-2 py-3 px-4 bg-purple-600 text-white rounded-lg font-medium transition-all duration-200 active:scale-95 hover:bg-purple-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
            >
              {isProcessing && processingImageIndex === selectedImageIndex ? <LoadingSpinner /> : <BrainIcon />}
              <span className="text-sm">고급 분석</span>
            </button>

            <button
              onClick={analyzeAllImages}
              disabled={images.length === 0 || isProcessing}
              className="flex items-center justify-center gap-2 py-3 px-4 bg-orange-600 text-white rounded-lg font-medium transition-all duration-200 active:scale-95 hover:bg-orange-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
            >
              {isProcessing && processingImageIndex === -1 ? <LoadingSpinner /> : <AllIcon />}
              <span className="text-sm">전체 일괄 분석</span>
            </button>
          </div>

          {/* 냉장고 저장 및 불러오기 버튼들 */}
          {showSaveButton && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-4 p-3 bg-green-50 border border-green-200 rounded-lg">
              <button
                onClick={saveToMongoDB}
                disabled={isSaving || fridgeIngredients.length === 0}
                className="flex items-center justify-center gap-2 py-3 px-4 bg-green-600 text-white rounded-lg font-medium transition-all duration-200 active:scale-95 hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
              >
                {isSaving ? <LoadingSpinner /> : <SaveIcon />}
                <span className="text-sm">
                  {isSaving ? '저장 중...' : `냉장고 저장 (${fridgeIngredients.length}종류)`}
                </span>
              </button>

              <button
                onClick={loadFromMongoDB}
                className="flex items-center justify-center gap-2 py-3 px-4 bg-blue-600 text-white rounded-lg font-medium transition-all duration-200 active:scale-95 hover:bg-blue-700"
              >
                <CheckIcon />
                <span className="text-sm">데이터 불러오기</span>
              </button>
            </div>
          )}

          {/* 신뢰도 설정 */}
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2 min-w-fit">
              <SettingsIcon />
              <span className="text-sm font-medium text-gray-700 whitespace-nowrap">신뢰도</span>
            </div>
            <div className="flex-1 px-2">
              <input
                type="range"
                min="0.1"
                max="0.9"
                step="0.1"
                value={confidence}
                onChange={(e) => setConfidence(parseFloat(e.target.value))}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer"
              />
            </div>
            <span className="text-sm font-medium text-gray-600 min-w-[2.5rem] text-center">
              {confidence.toFixed(1)}
            </span>
          </div>

          {/* 분석 전 초기화 옵션 */}
          <div className="flex items-center gap-3 pt-2 border-t border-gray-200">
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={clearBeforeAnalysis}
                onChange={(e) => setClearBeforeAnalysis(e.target.checked)}
                className="w-4 h-4 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500"
              />
              <span className="text-sm text-gray-700">분석 전 냉장고 초기화</span>
            </label>
          </div>
        </div>

        {/* 메인 콘텐츠 */}
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-4">
          
          {/* 이미지 갤러리 및 표시 영역 */}
          <div className="lg:col-span-3">
            <div className="bg-white rounded-xl shadow-sm p-4">
              
              {/* 이미지 갤러리 */}
              {images.length > 0 && (
                <div className="mb-4">
                  <div className="flex items-center justify-between mb-3">
                    <h3 className="text-sm font-semibold text-gray-700">
                      업로드된 이미지 ({images.length}개)
                    </h3>
                    <button
                      onClick={() => setImages([])}
                      className="text-xs text-red-500 hover:text-red-700 hover:bg-red-50 px-2 py-1 rounded transition-colors"
                    >
                      전체 삭제
                    </button>
                  </div>
                  <div className="grid grid-cols-3 sm:grid-cols-4 gap-2 max-h-32 overflow-y-auto">
                    {images.map((image, index) => (
                      <div
                        key={image.id}
                        className={`relative cursor-pointer rounded-lg border-2 overflow-hidden transition-all duration-200 ${
                          selectedImageIndex === index 
                            ? 'border-blue-500 ring-2 ring-blue-200' 
                            : 'border-gray-200 hover:border-blue-300'
                        } ${
                          processingImageIndex === index ? 'ring-2 ring-green-300' : ''
                        }`}
                        onClick={() => setSelectedImageIndex(index)}
                      >
                        <img
                          src={image.dataUrl}
                          alt={`업로드 ${index + 1}`}
                          className="w-full h-16 object-cover"
                        />
                        <div className="absolute top-1 left-1 bg-black bg-opacity-60 text-white text-xs px-1 rounded">
                          {index + 1}
                        </div>
                        {image.processed && (
                          <div className="absolute top-1 right-1 bg-green-500 text-white text-xs px-1 rounded">
                            ✓
                          </div>
                        )}
                        {processingImageIndex === index && (
                          <div className="absolute inset-0 bg-green-500 bg-opacity-30 flex items-center justify-center">
                            <LoadingSpinner />
                          </div>
                        )}
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            removeImage(image.id);
                          }}
                          className="absolute top-1 right-1 bg-red-500 text-white text-xs w-5 h-5 rounded-full flex items-center justify-center hover:bg-red-600 transition-colors"
                        >
                          ×
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* 메인 이미지 표시 영역 */}
              <div 
                className={`border-2 border-dashed rounded-xl min-h-[200px] sm:min-h-[300px] lg:min-h-[400px] flex items-center justify-center transition-all duration-300 cursor-pointer ${
                  isDragOver 
                    ? 'border-blue-500 bg-blue-50' 
                    : 'border-gray-300 hover:border-blue-400 hover:bg-blue-50'
                }`}
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
                onDrop={handleDrop}
                onClick={() => fileInputRef.current?.click()}
              >
                {images.length > 0 && selectedImageIndex >= 0 && images[selectedImageIndex] ? (
                  <div className="w-full h-full flex flex-col">
                    <div className="flex-1 flex items-center justify-center">
                      <img
                        src={images[selectedImageIndex].dataUrl}
                        alt={`선택된 이미지 ${selectedImageIndex + 1}`}
                        className="max-w-full max-h-full rounded-lg object-contain"
                        style={{ maxHeight: '50vh' }}
                      />
                    </div>
                    <div className="mt-3 text-center">
                      <p className="text-sm text-gray-600">
                        이미지 {selectedImageIndex + 1} / {images.length} - {images[selectedImageIndex].name}
                        {images[selectedImageIndex].processed && (
                          <span className="ml-2 text-green-600 font-semibold">✓ 분석완료</span>
                        )}
                      </p>
                    </div>
                  </div>
                ) : (
                  <div className="text-center text-gray-500 p-6">
                    <div className="text-4xl sm:text-5xl mb-3">🧊</div>
                    <p className="text-sm sm:text-base font-medium mb-1">
                      {isDragOver ? '파일을 놓아주세요' : '냉장고 사진들을 업로드하세요'}
                    </p>
                    <p className="text-xs sm:text-sm text-gray-400">
                      {isDragOver ? '' : '여러 이미지를 한번에 선택하거나 드래그하세요'}
                    </p>
                  </div>
                )}
              </div>

              {/* 진행 상태 */}
              {isProcessing && (
                <div className="mt-4 bg-blue-50 border border-blue-200 rounded-lg p-3">
                  <div className="flex items-center gap-3">
                    <LoadingSpinner />
                    <span className="text-blue-800 text-sm font-medium">{processingStep}</span>
                  </div>
                  {processingImageIndex >= 0 && (
                    <div className="mt-2 text-xs text-blue-600">
                      현재 처리 중인 이미지: {processingImageIndex + 1} / {images.length}
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>

          {/* 결과 표시 영역 */}
          <div className="lg:col-span-2">
            {/* 냉장고 속 식재료 대시보드 */}
            <div className="bg-white rounded-xl shadow-sm mb-4">
              <div className="p-4 border-b border-gray-200">
                <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <FridgeIcon />
                    <h3 className="text-lg font-semibold text-gray-800">냉장고 속 식재료</h3>
                  </div>
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => setShowManualAdd(true)}
                      className="flex items-center gap-1 px-3 py-1.5 bg-blue-600 text-white text-sm rounded-lg hover:bg-blue-700 transition-colors"
                    >
                      <EditIcon />
                      <span>직접추가</span>
                    </button>
                    <button
                      onClick={() => setFridgeIngredients([])}
                      className="text-xs text-red-500 hover:text-red-700 hover:bg-red-50 px-2 py-1 rounded transition-colors"
                    >
                      전체 삭제
                    </button>
                  </div>
                </div>
                <div className="text-sm text-gray-500">
                  총 {fridgeIngredients.length}개
                </div>
              </div>
              <div className="p-4" style={{ minHeight: '250px', maxHeight: '400px', overflowY: 'auto' }}>
                {fridgeIngredients.length > 0 ? (
                  <div className="space-y-3">
                    {fridgeIngredients.map((ingredient) => (
                      <div key={ingredient.id} className="bg-gradient-to-r from-blue-50 to-green-50 border border-gray-200 rounded-lg p-4 transition-all duration-200 hover:shadow-md">
                        <div className="flex items-center justify-between mb-3">
                          <h4 className="font-semibold text-gray-800 text-lg">{ingredient.name}</h4>
                          <button
                            onClick={() => removeIngredient(ingredient.id)}
                            className="text-red-500 hover:text-red-700 hover:bg-red-50 rounded-full p-1 transition-colors"
                          >
                            <DeleteIcon />
                          </button>
                        </div>
                        
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-3">
                            <button
                              onClick={() => updateIngredientQuantity(ingredient.id, ingredient.quantity - 1)}
                              disabled={ingredient.quantity <= 1}
                              className="w-8 h-8 rounded-full bg-red-100 text-red-600 hover:bg-red-200 disabled:bg-gray-100 disabled:text-gray-400 disabled:cursor-not-allowed flex items-center justify-center transition-colors"
                            >
                              <MinusIcon />
                            </button>
                            
                            <div className="flex flex-col items-center">
                              <span className="text-2xl font-bold text-blue-600">{ingredient.quantity}</span>
                              <span className="text-xs text-gray-500">개</span>
                            </div>
                            
                            <button
                              onClick={() => updateIngredientQuantity(ingredient.id, ingredient.quantity + 1)}
                              className="w-8 h-8 rounded-full bg-green-100 text-green-600 hover:bg-green-200 flex items-center justify-center transition-colors"
                            >
                              <PlusIcon />
                            </button>
                          </div>
                          
                          <div className="text-xs text-gray-500 bg-white bg-opacity-70 px-2 py-1 rounded-full">
                            {ingredient.source === 'manual' && '✏️ 수동'}
                            {ingredient.source === 'detection' && '🎯 탐지'}
                            {ingredient.source === 'gemini' && '🧠 AI'}
                            {ingredient.confidence && (
                              <span className="ml-1 text-green-600 font-semibold">
                                {(ingredient.confidence * 100).toFixed(0)}%
                              </span>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center text-gray-500 py-12">
                    <div className="text-4xl mb-4">🥬</div>
                    <h4 className="text-lg font-medium mb-2">냉장고가 비어있습니다</h4>
                    <p className="text-sm mb-4">냉장고 사진을 업로드하고 분석하거나</p>
                    <button
                      onClick={() => setShowManualAdd(true)}
                      className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white text-sm rounded-lg hover:bg-blue-700 transition-colors"
                    >
                      <EditIcon />
                      <span>직접 추가하기</span>
                    </button>
                  </div>
                )}
              </div>
              
              {fridgeIngredients.length > 0 && (
                <div className="px-4 py-3 bg-gray-50 border-t border-gray-200 rounded-b-xl">
                  <div className="flex items-center justify-between text-sm">
                    <span className="text-gray-600">총 수량</span>
                    <span className="font-semibold text-gray-800">
                      {fridgeIngredients.reduce((sum, item) => sum + item.quantity, 0)}개
                    </span>
                  </div>
                </div>
              )}
            </div>

            {/* 분석 결과 표시 */}
            <div className="bg-white rounded-xl shadow-sm overflow-hidden">
              <div className="p-4">
                {/* 탭 네비게이션 */}
                <div className="flex border-b border-gray-200 mb-4">
                  <button
                    onClick={() => setActiveTab('detection')}
                    className={`flex items-center gap-2 px-4 py-2 text-sm font-medium transition-colors ${
                      activeTab === 'detection'
                        ? 'text-blue-600 border-b-2 border-blue-600'
                        : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    <EyeIcon />
                    객체탐지
                  </button>
                  <button
                    onClick={() => setActiveTab('ocr')}
                    className={`flex items-center gap-2 px-4 py-2 text-sm font-medium transition-colors ${
                      activeTab === 'ocr'
                        ? 'text-blue-600 border-b-2 border-blue-600'
                        : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    <FileTextIcon />
                    텍스트추출
                  </button>
                  <button
                    onClick={() => setActiveTab('gemini')}
                    className={`flex items-center gap-2 px-4 py-2 text-sm font-medium transition-colors ${
                      activeTab === 'gemini'
                        ? 'text-blue-600 border-b-2 border-blue-600'
                        : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    <BrainIcon />
                    AI분석
                  </button>
                </div>

                {/* 탭 내용 */}
                <div className="min-h-[200px]">
                  {activeTab === 'detection' && (
                    <div>
                      <h3 className="text-sm font-semibold text-gray-800 mb-3">객체 탐지 결과</h3>
                      {images.length > 0 && selectedImageIndex >= 0 && detectionResults[images[selectedImageIndex]?.id] ? (
                        <div className="space-y-2">
                          <div className="text-xs text-gray-600 mb-2">
                            이미지 {selectedImageIndex + 1}: 총 {detectionResults[images[selectedImageIndex].id].detections?.length || 0}개 탐지
                          </div>
                          {detectionResults[images[selectedImageIndex].id].detections?.length > 0 ? (
                            detectionResults[images[selectedImageIndex].id].detections.map((detection, index) => (
                              <div key={index} className="p-3 bg-gray-50 rounded-lg">
                                <div className="flex justify-between items-center">
                                  <span className="text-sm font-medium text-blue-600">
                                    {detection.class}
                                  </span>
                                  <span className="text-xs font-semibold px-2 py-1 rounded-full bg-green-100 text-green-700">
                                    {(detection.confidence * 100).toFixed(1)}%
                                  </span>
                                </div>
                              </div>
                            ))
                          ) : (
                            <p className="text-sm text-gray-500">탐지된 객체가 없습니다.</p>
                          )}
                        </div>
                      ) : (
                        <p className="text-sm text-gray-500">이미지를 선택하고 분석해주세요.</p>
                      )}
                    </div>
                  )}

                  {activeTab === 'ocr' && (
                    <div>
                      <h3 className="text-sm font-semibold text-gray-800 mb-3">텍스트 추출 결과</h3>
                      {images.length > 0 && selectedImageIndex >= 0 && ocrResults[images[selectedImageIndex]?.id] ? (
                        <div className="space-y-3">
                          <div className="text-xs text-gray-600 mb-2">
                            이미지 {selectedImageIndex + 1}에서 추출된 텍스트:
                          </div>
                          <div className="p-3 bg-gray-50 rounded-lg">
                            <p className="text-sm text-gray-800 whitespace-pre-wrap">
                              {ocrResults[images[selectedImageIndex].id].text || '추출된 텍스트가 없습니다.'}
                            </p>
                          </div>
                          {ocrResults[images[selectedImageIndex].id].confidence && (
                            <div className="text-xs text-gray-600">
                              신뢰도: {(ocrResults[images[selectedImageIndex].id].confidence * 100).toFixed(1)}%
                            </div>
                          )}
                        </div>
                      ) : (
                        <p className="text-sm text-gray-500">이미지를 선택하고 OCR 분석을 진행해주세요.</p>
                      )}
                    </div>
                  )}

                  {activeTab === 'gemini' && (
                    <div>
                      <h3 className="text-sm font-semibold text-gray-800 mb-3">AI 분석 결과</h3>
                      {images.length > 0 && selectedImageIndex >= 0 && geminiResults[images[selectedImageIndex]?.id] ? (
                        <div className="space-y-3">
                          <div className="text-xs text-gray-600 mb-2">
                            이미지 {selectedImageIndex + 1} AI 분석 결과:
                          </div>
                          <div className="p-3 bg-gradient-to-r from-purple-50 to-blue-50 rounded-lg border border-purple-200">
                            <div className="flex items-center gap-2 mb-2">
                              <BrainIcon />
                              <span className="text-sm font-semibold text-purple-700">추론된 식품명</span>
                            </div>
                            <p className="text-lg font-bold text-gray-800">
                              {geminiResults[images[selectedImageIndex].id].text}
                            </p>
                          </div>
                          {geminiResults[images[selectedImageIndex].id].extractedText && (
                            <div className="p-3 bg-gray-50 rounded-lg">
                              <div className="text-xs text-gray-600 mb-1">분석에 사용된 텍스트:</div>
                              <p className="text-sm text-gray-700">
                                {geminiResults[images[selectedImageIndex].id].extractedText}
                              </p>
                            </div>
                          )}
                        </div>
                      ) : (
                        <p className="text-sm text-gray-500">이미지를 선택하고 고급 분석을 진행해주세요.</p>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* 상태바 */}
        <div className="mt-4 bg-white rounded-xl shadow-sm p-3">
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
            <span className="text-xs sm:text-sm text-gray-700 truncate flex-1">
              {statusMessage}
            </span>
          </div>
        </div>
      </div>

      {/* 직접 추가 모달 */}
      {showManualAdd && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-md">
            <div className="p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-bold text-gray-800">식재료 직접 추가</h2>
                <button
                  onClick={closeManualAdd}
                  className="text-gray-400 hover:text-gray-600 p-1"
                >
                  <CloseIcon />
                </button>
              </div>
              
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    식재료 이름
                  </label>
                  <input
                    ref={manualInputRef}
                    type="text"
                    value={manualIngredientName}
                    onChange={(e) => setManualIngredientName(e.target.value)}
                    onKeyPress={handleManualInputKeyPress}
                    placeholder="예: 사과, 우유, 당근..."
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    수량
                  </label>
                  <div className="flex items-center gap-3">
                    <button
                      onClick={() => setManualIngredientQuantity(Math.max(1, manualIngredientQuantity - 1))}
                      className="w-10 h-10 rounded-full bg-red-100 text-red-600 hover:bg-red-200 flex items-center justify-center transition-colors"
                    >
                      <MinusIcon />
                    </button>
                    
                    <div className="flex flex-col items-center min-w-[60px]">
                      <span className="text-2xl font-bold text-blue-600">{manualIngredientQuantity}</span>
                      <span className="text-xs text-gray-500">개</span>
                    </div>
                    
                    <button
                      onClick={() => setManualIngredientQuantity(manualIngredientQuantity + 1)}
                      className="w-10 h-10 rounded-full bg-green-100 text-green-600 hover:bg-green-200 flex items-center justify-center transition-colors"
                    >
                      <PlusIcon />
                    </button>
                  </div>
                </div>
              </div>
              
              <div className="flex gap-3 mt-6">
                <button
                  onClick={closeManualAdd}
                  className="flex-1 py-3 px-4 bg-gray-200 text-gray-800 rounded-lg font-medium hover:bg-gray-300 transition-colors"
                >
                  취소
                </button>
                <button
                  onClick={addManualIngredient}
                  disabled={isAddingManual || !manualIngredientName.trim()}
                  className="flex-1 py-3 px-4 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-colors flex items-center justify-center gap-2"
                >
                  {isAddingManual ? <LoadingSpinner /> : <PlusIcon />}
                  <span>{isAddingManual ? '추가 중...' : '추가하기'}</span>
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default FoodDetectionApp;
